class Solution {
    public long findMaximumNumber(long k, int x) {
        long left = 0, right = (long) 1e18;
        while (left < right) {
            long mid = left + (right - left + 1) / 2;
            long cost = getCost(mid, x);
            if (cost <= k) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }

    private long getCost(long num, int x) {
        long cost = 0;
        for (long i = 1; i <= num; i += 1) {
            cost += getPrice(i, x);
        }
        return cost;
    }

    private int getPrice(long num, int x) {
        int price = 0;
        long pos = x;
        while (num > 0) {
            if ((num & 1) == 1) {
                price++;
            }
            num >>= 1;
            pos++;
            if (pos > 64) break; // Assuming 64-bit integer
        }
        return price;
    }
}
